        cin>>M;
        while(M!=-1){
            for(int j=3;j>=1;j--){
                if(basebag[j]==1){
                    basebag[j]=0;
                    if(j+M>=4)
                    total++;
                    else 
                       basebag[j+M]=1; 
                }
            }
            if(M==4)
                total++;
            else
                basebag[M]=1;

            cin>>M;
        }
    }
    cout<<"Point: "<<total;
}

