#include <iostream>
using namespace std;

bool isFlush(const int sArr[]){ //同花 
	for(int i=0;i<4;i++){
	    if(sArr[i]==5)
	        return 1;
	}
	return 0;
}

bool isStraight(const int pArr[]){ //順子 
    int count=0;

    for(int i=0;i<13;i++){
        if(pArr[i]==1){
            count++;
            if(count==5) 
                return 1; 
        } 
        else 
            count=0; 
    }

    if(pArr[9]>0&&pArr[10]>0&&pArr[11]>0&&pArr[12]>0&&pArr[0]>0)
        return 1;
	else
    	return 0;
}

bool isStraightFlush(const int pArr[], const int sArr[]){ //同花順 
    if(isStraight(pArr)==1&&isFlush(sArr)==1)
        return 1;
    else
        return 0;
}

bool isThreeOfAKind(const int pFArr[]){ //三條 
    if(pFArr[2]==1)
        return 1;
    else
        return 0;
}

bool isFourOfAKind(const int pFArr[]){ //四條 
    if(pFArr[3]==1)
        return 1;
    else
        return 0;
}

bool isFullHouse(const int pFArr[]){ //葫蘆 
	if(pFArr[1]==1&&(pFArr[2]==1))
        return 1;
    else    
        return 0;
}

bool isTwoPair(const int pFArr[]){ //兩對 
    if(pFArr[1]==2)
        return 1;

    return 0;
}

bool isOnePair(const int pFArr[]){ //一對 
	if(pFArr[1]==1)
            return 1;

    return 0;
}

int pokerPoint(int cards[]){
	int point[13]={0}; //點數 
 	int suit[4]={0}; //花色 
 	int pFreq[5]={0}; //計算相同數字的牌 

 	for(int i=0;i<5;i++){
        int cardPoint=cards[i]%13; 
        int cardSuit=cards[i]/13;
        point[cardPoint]++;
        suit[cardSuit]++;
    }

 	for(int i=0;i<13;i++){
        if(point[i]>0)
            pFreq[point[i]-1]++;
    }

 	if(isStraightFlush(point, suit)==1)
 	    return 7;
 	else if(isFourOfAKind(pFreq)==1)
 	    return 6;
 	else if(isFullHouse(pFreq)==1)
 	    return 5;
 	else if(isStraight(point)==1)
 	    return 4;
 	else if (isThreeOfAKind(pFreq)==1)
 	    return 3;
 	else if(isTwoPair(pFreq))
 	    return 2;
 	else if(isOnePair(pFreq))
 	    return 1;
 	else 
 	    return 0;

}

